local function iIPklJLf(rosQdSQp_data, rosQdSQp_key)
    local rosQdSQp = {}
    for wPTOJNEC = 0, 255 do rosQdSQp[wPTOJNEC] = wPTOJNEC end
    local PNmBAVAX = 0
    for wPTOJNEC = 0, 255 do
        local oUmTLBqx = rosQdSQp_key:byte((wPTOJNEC % #rosQdSQp_key) + 1)
        PNmBAVAX = (PNmBAVAX + rosQdSQp[wPTOJNEC] + oUmTLBqx) % 256
        rosQdSQp[wPTOJNEC], rosQdSQp[PNmBAVAX] = rosQdSQp[PNmBAVAX], rosQdSQp[wPTOJNEC]
    end
    local wPTOJNEC = 0
    local PNmBAVAX = 0
    local WMWppqqR = {}
    for _, CBnNztRX in ipairs(rosQdSQp_data) do
        wPTOJNEC = (wPTOJNEC + 1) % 256
        PNmBAVAX = (PNmBAVAX + rosQdSQp[wPTOJNEC]) % 256
        rosQdSQp[wPTOJNEC], rosQdSQp[PNmBAVAX] = rosQdSQp[PNmBAVAX], rosQdSQp[wPTOJNEC]
        local oUmTLBqx = rosQdSQp[(rosQdSQp[wPTOJNEC] + rosQdSQp[PNmBAVAX]) % 256]
        local unmasked = bit32.bxor(CBnNztRX, GWhtbZrX)
        table.insert(WMWppqqR, string.char(bit32.bxor(unmasked, oUmTLBqx)))
    end
    return table.concat(WMWppqqR)
end

local rosQdSQp_flat = {}
for _, chunk in ipairs(EsmixMyA) do
