return function(oPnrcQCs, ...)
    -- Anti-Hook & Environment Protection Shield
    local function nFIcIuzv()
        local isTampered = false
        pcall(function()
            if hookfunction or hookmetatable or getrawmetatable then
                local g = getgenv and getgenv() or _G
                if g and (rawget(g, "loadstring_hooked") or rawget(g, "dump_active")) then
                    isTampered = true
                end
            end
        end)
        return isTampered
    end

    if nFIcIuzv() then
        table.clear(rosQdSQp_flat)
        return function() end
    end

    local decrypted = iIPklJLf(rosQdSQp_flat, oPnrcQCs)
    local RjYSfLMX, vnPXIYgJ = loadstring(decrypted)
    
    -- Immediate Memory Sanitation: Scrub buffer pointers from GC
    table.clear(rosQdSQp_flat)
    rosQdSQp_flat = nil
    
    if RjYSfLMX then 
        local result = RjYSfLMX(oPnrcQCs, ...)
        decrypted = nil
        RjYSfLMX = nil
        if type(result) == "function" then
            return result(oPnrcQCs, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "storage_hunters" .. "): " .. tostring(vnPXIYgJ)) 
    end
end
